import pyotp
import qrcode
import base64
import os
from flask import Flask, request, jsonify

app = Flask(__name__)

# Generate a TOTP secret for a user
def generate_totp_secret():
    return base64.b32encode(os.urandom(10)).decode('utf-8')

# Create a QR code for the TOTP secret
def create_qr_code(secret, user):
    totp_uri = pyotp.totp.TOTP(secret).provisioning_uri(name=user, issuer_name="YourApp")
    qr = qrcode.make(totp_uri)
    qr.save(f"{user}_qrcode.png")

# Validate TOTP code
def validate_totp(secret, code):
    totp = pyotp.TOTP(secret)
    return totp.verify(code, valid_window=1)  # Allow a 1-step window for time drift

@app.route('/generate', methods=['POST'])
def generate():
    user = request.json.get('user')
    secret = generate_totp_secret()
    create_qr_code(secret, user)
    return jsonify({"secret": secret, "message": "QR code generated and saved."})

@app.route('/validate', methods=['POST'])
def validate():
    user = request.json.get('user')
    secret = request.json.get('secret')
    code = request.json.get('code')
    if validate_totp(secret, code):
        return jsonify({"message": "TOTP code is valid."})
    else:
        return jsonify({"message": "Invalid TOTP code."}), 400

if __name__ == '__main__':
    app.run(debug=True)